import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { DataService, SearchResult } from './data.service';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css'],
})
export class HomeComponent implements OnInit {
  searchInputs = [''];
  navSearch = '';
  suggestions: string[] = [];
  activeType: 'nav' | 'main' | null = null;
  activeIndex: number | null = null;
  suggestionCursor = -1;
  allKeywords: string[] = [];
  loadingKeywords = false;
  error = '';

  constructor(private router: Router, private dataService: DataService) {}

  ngOnInit(): void {
    this.loadingKeywords = true;
    this.dataService.loadData().subscribe({
      next: () => {
        this.allKeywords = this.dataService.getKeywordsList();
        this.loadingKeywords = false;
      },
      error: () => {
        this.loadingKeywords = false;
      },
    });
  }

  addField(): void {
    if (this.searchInputs.length < 3) {
      this.searchInputs.push('');
    }
  }

  setActiveIndex(index: number): void {
    this.activeType = 'main';
    this.activeIndex = index;
    this.suggestionCursor = -1;
    this.updateSuggestions(this.searchInputs[index] || '');
  }

  setActiveNav(): void {
    this.activeType = 'nav';
    this.activeIndex = null;
    this.suggestionCursor = -1;
    this.updateSuggestions(this.navSearch || '');
  }

  updateSuggestions(value: string): void {
    const query = (value || '').trim().toLowerCase();
    if (!query) {
      this.suggestions = [];
      return;
    }
    this.suggestions = this.allKeywords
      .filter((item) => item.toLowerCase().includes(query))
      .slice(0, 6);
  }

  selectSuggestion(item: string, type: 'nav' | 'main', index?: number): void {
    if (type === 'nav') {
      this.navSearch = item;
    } else if (index !== undefined) {
      this.searchInputs[index] = item;
    }
    this.hideSuggestions();
  }

  hideSuggestions(): void {
    this.suggestions = [];
    this.activeType = null;
    this.activeIndex = null;
    this.suggestionCursor = -1;
  }

  handleSuggestionKey(event: KeyboardEvent, type: 'nav' | 'main', index?: number): void {
    if (!this.suggestions.length) {
      if (event.key === 'Enter') {
        event.preventDefault();
        type === 'nav' ? this.searchNav() : this.doSearch();
      }
      return;
    }

    if (event.key === 'ArrowDown') {
      event.preventDefault();
      this.suggestionCursor = Math.min(this.suggestionCursor + 1, this.suggestions.length - 1);
      return;
    }

    if (event.key === 'ArrowUp') {
      event.preventDefault();
      this.suggestionCursor = Math.max(this.suggestionCursor - 1, 0);
      return;
    }

    if (event.key === 'Enter') {
      event.preventDefault();
      if (this.suggestionCursor >= 0 && this.suggestionCursor < this.suggestions.length) {
        this.selectSuggestion(this.suggestions[this.suggestionCursor], type, index);
      } else {
        type === 'nav' ? this.searchNav() : this.doSearch();
      }
      return;
    }

    if (event.key === 'Escape') {
      this.hideSuggestions();
    }
  }

  doSearch(): void {
    this.error = '';
    const queries = this.searchInputs.map((item) => item.trim()).filter((item) => item);
    if (!queries.length) {
      this.error = 'Inserisci almeno una preoccupazione per iniziare.';
      return;
    }
    this.hideSuggestions();
    this.dataService.loadData().subscribe({
      next: () => {
        const results = this.dataService.findTop3Categories(queries);
        if (!results.length) {
          this.error = 'Nessuna categoria trovata. Prova con parole diverse.';
          return;
        }
        this.router.navigate(['/risultati'], {
          queryParams: { data: JSON.stringify(results) },
        });
      },
      error: () => {
        this.error = 'Errore di rete. Riprova più tardi.';
      },
    });
  }

  searchNav(): void {
    const query = (this.navSearch || '').trim();
    if (!query) {
      return;
    }
    this.searchInputs = [query];
    this.doSearch();
    this.hideSuggestions();
  }
}
