  <a class="navbar-brand-text text-decoration-none" routerLink="/">🌿 Educazione Digitale Familiare</a>

  <div class="d-flex align-items-center gap-2 flex-wrap">
      <a class="nav-link-custom text-decoration-none me-4" href="#come-funziona">Come funziona</a>
      <a class="nav-link-custom text-decoration-none me-4" href="#esperti">Esperti</a>
      <a class="nav-link-custom text-decoration-none me-4" href="#temi">Temi</a>

      <div class="d-flex gap-2 ms-2 nav-search-wrap">
        <input
          class="search-bar"
          type="search"
          placeholder="Cerca la tua preoccupazione…"
          [(ngModel)]="navSearch"
          (focus)="setActiveNav()"
          (input)="updateSuggestions(navSearch)"
          (keydown)="handleSuggestionKey($event, 'nav')"
          autocomplete="off"
        />
        <button id="navSearchButton" class="btn-search" (click)="searchNav()">Cerca</button>
        <div class="autocomplete-list" *ngIf="activeType === 'nav' && suggestions.length">
          <div
            class="autocomplete-item"
            *ngFor="let option of suggestions; let idx = index"
            [class.active]="idx === suggestionCursor"
            (mousedown)="selectSuggestion(option, 'nav')"
          >
            {{ option }}
          </div>
        </div>
      </div>
    </div>
  </nav>

