    <p>
      Descrivi la situazione con parole tue: ti mostreremo le aree più rilevanti con percorsi pratici.
    </p>

    <div class="multi-search-wrap">
      <div class="search-input-row" *ngFor="let item of searchInputs; let i = index">
        <div class="search-input-layer">
          <input
            class="search-big"
            type="search"
            [placeholder]="i === 0 ? 'es. mio figlio passa troppo tempo sullo smartphone...' : 'Aggiungi una nuova preoccupazione...'
            "
            [(ngModel)]="searchInputs[i]"
            (focus)="setActiveIndex(i)"
            (input)="updateSuggestions(searchInputs[i])"
            (keydown)="handleSuggestionKey($event, 'main', i)"
            autocomplete="off"
          />
          <div class="autocomplete-list" *ngIf="activeType === 'main' && activeIndex === i && suggestions.length">
            <div
              class="autocomplete-item"
              *ngFor="let option of suggestions; let idx = index"
              [class.active]="idx === suggestionCursor"
              (mousedown)="selectSuggestion(option, 'main', i)"
            >
              {{ option }}
            </div>
          </div>
        </div>
        <button class="btn-add" *ngIf="searchInputs.length < 3 && i === searchInputs.length - 1" (click)="addField()" title="Aggiungi una nuova preoccupazione">+</button>
